      rval sval frame_time !dist_to_player !previous_visibility
      (Ox_math.fixmul ~a:rval ~b:sval) (player_flags land player_flags_headlight_on) game_time;
    flush stderr);
  if Ox_math.fixmul ~a:rval ~b:sval < frame_time
