   so that firing logic and state sync behave correctly. *)
if !dist_to_player < f1_0 * 100
then object_animates := (if n_guns > 0 then 1 else 0)
else (
  current_state := !goal_state;
  object_animates := 0);
(* Phase: boss handling *)
if boss_flag <> 0
then (
  if !goal_state = ais_flin then goal_state := ais_fire;
  if !current_state = ais_flin then current_state := ais_fire;

