2041→void compute_vis_and_vec(object *objp, vms_vector *pos, ai_local *ailp, vms_vector *vec_to_player, int *player_visibility, robot_info *robptr, int *flag)
2042→{
2043→#ifdef USE_OX_BRIDGE
2044→	if (!*flag) {
2045→		ensure_fvi_data_callbacks_registered();
2046→		int n_segments = Highest_segment_index + 1;
2047→		int n_objects = Highest_object_index + 1;
2048→		int objp_objnum = (int)(objp - Objects);
2049→
2050→		// v2 packed format: header(8) + pv_ext(20) + cvv_ext(19) = 47 ints
2051→		int packed_len = 8 + 20 + 19;
2052→		int32_t packed[47];
2053→
2054→		// v2 header
2055→		packed[0] = n_objects;
2056→		packed[1] = 1;  // is_d2
2057→		packed[2] = objp_objnum;
2058→		packed[3] = Players[Player_num].objnum;
2059→		packed[4] = GameTime;
2060→		packed[5] = (Game_mode & GM_MULTI_COOP) ? 1 : 0;
2061→		packed[6] = 0;  // physics_cheat
2062→		packed[7] = n_segments;
2063→
2064→		// pv extension (20 ints at offset 8)
2065→		packed[8 + 0] = pos->x;
2066→		packed[8 + 1] = pos->y;
2067→		packed[8 + 2] = pos->z;
2068→		packed[8 + 3] = objp->pos.x;
2069→		packed[8 + 4] = objp->pos.y;
2070→		packed[8 + 5] = objp->pos.z;
2071→		packed[8 + 6] = objp->segnum;
2072→		packed[8 + 7] = objp->orient.fvec.x;
2073→		packed[8 + 8] = objp->orient.fvec.y;
2074→		packed[8 + 9] = objp->orient.fvec.z;
2075→		packed[8 + 10] = robptr->field_of_view[Difficulty_level];
2076→		packed[8 + 11] = 0;  // vec_to_player (computed by OCaml)
2077→		packed[8 + 12] = 0;
2078→		packed[8 + 13] = 0;
2079→		packed[8 + 14] = Believed_player_pos.x;
2080→		packed[8 + 15] = Believed_player_pos.y;
2081→		packed[8 + 16] = Believed_player_pos.z;
2082→		packed[8 + 17] = Overall_agitation;
2083→		packed[8 + 18] = Players[Player_num].objnum;
2084→		packed[8 + 19] = objp->ctype.ai_info.SUB_FLAGS;
2085→
2086→		// cvv extension (19 ints at offset 28)
2087→		int cloak_index = objp_objnum % MAX_AI_CLOAK_INFO;
2088→		packed[28 + 0] = (Players[Player_num].flags & PLAYER_FLAGS_CLOAKED) ? 1 : 0;
2089→		packed[28 + 1] = Difficulty_level;
2090→		packed[28 + 2] = Ai_cloak_info[cloak_index].last_time;
2091→		packed[28 + 3] = Ai_cloak_info[cloak_index].last_position.x;
2092→		packed[28 + 4] = Ai_cloak_info[cloak_index].last_position.y;
2093→		packed[28 + 5] = Ai_cloak_info[cloak_index].last_position.z;
2094→		packed[28 + 6] = (int32_t)P_Rand_get_state();
2095→		packed[28 + 7] = ailp->next_misc_sound_time;
2096→		packed[28 + 8] = ailp->next_fire;
2097→		packed[28 + 9] = ailp->previous_visibility;
2098→		packed[28 + 10] = ailp->time_player_seen;
2099→		packed[28 + 11] = ailp->time_player_sound_attacked;
2100→		packed[28 + 12] = objp->ctype.ai_info.GOAL_STATE;
2101→		packed[28 + 13] = objp->ctype.ai_info.CURRENT_STATE;
2102→		packed[28 + 14] = robptr->see_sound;
2103→		packed[28 + 15] = robptr->attack_sound;
2104→		packed[28 + 16] = 0;  // Player_exploded (D2 doesn't use it)
2105→		packed[28 + 17] = ailp->next_fire2;
2106→		packed[28 + 18] = ailp->player_awareness_type;
2107→
2108→		int32_t out[28];
2109→		cd_ox_compute_vis_and_vec_v2(packed, packed_len, out);
2110→
2111→		*player_visibility = out[0];
2112→		vec_to_player->x = out[1]; vec_to_player->y = out[2]; vec_to_player->z = out[3];
2113→		if (out[7])  // need_move_center
2114→		{
2115→			pos->x = out[4]; pos->y = out[5]; pos->z = out[6];
2116→			move_towards_segment_center(objp);
2117→		}
2118→		Hit_type = out[9];
